class Solution {
    public boolean canTransform(String start, String result) {
        if (start.length() != result.length()) return false;
        int[] s = new int[start.length()];
        int[] r = new int[result.length()];
        for (int i = 0; i < start.length(); i++) {
            if (start.charAt(i) == 'L') s[i] = -1;
            else if (start.charAt(i) == 'R') s[i] = 1;
        }
        for (int i = 0; i < result.length(); i++) {
            if (result.charAt(i) == 'L') r[i] = -1;
            else if (result.charAt(i) == 'R') r[i] = 1;
        }
        for (int i = 0; i < start.length(); i++) {
            if (s[i] != r[i] && (s[i] == 0 || r[i] == 0)) return false;
        }
        int Xs = 0, Xr = 0;
        for (int i = 0; i < start.length(); i++) {
            if (start.charAt(i) == 'X') Xs++;
            if (result.charAt(i) == 'X') Xr++;
            if (Xs < Xr) return false;
        }
        return Xs == Xr;
    }
}
